// Sensing Components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder measuring the swing angle of the crane counterweight"
    DTDFVocab:producedData CraneTelemetryTransmitted
]
instance AnemometerSensor : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed affecting crane operation"
    DTDFVocab:producedData CraneTelemetryTransmitted
]
instance CartMotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder on the cart axis stepper motor reporting cart position"
    DTDFVocab:producedData CraneTelemetryTransmitted
]
instance HoistMotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder on the hoist axis stepper motor reporting hoist height"
    DTDFVocab:producedData CraneTelemetryTransmitted
]

// Data Transmission
instance CraneTelemetryTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder, AnemometerSensor, CartMotorPositionEncoder, HoistMotorPositionEncoder
]

// Telemetry Data
instance CraneTimeSeriesData : DTDFVocab:Data [
    base:desc "Time‑series telemetry of motor positions, swing angle, wind speed, and timestamps"
    DTDFVocab:inputTo PhysicalCraneInterfaceEnabler
    DTDFVocab:fromData CraneTelemetryTransmitted
]

// Enablers
instance PhysicalCraneInterfaceEnabler : DTDFVocab:Enabler [
    base:desc "Python Physical Crane Interface that streams telemetry to the MQTT broker"
    DTDFVocab:enables MQTTPublisherService
]
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker used for real‑time data distribution"
    DTDFVocab:enables LoggingIngestionService
]
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB instance that stores historical telemetry"
    DTDFVocab:enables DataStorageService
]
instance GrafanaDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Grafana instance that visualizes time‑series data for operator dashboards"
    DTDFVocab:enables DashboardVisualizationService
]
instance TrajectoryGeneratorEnabler : DTDFVocab:Enabler [
    base:desc "Service enabling trajectory generation using kinematic models"
    DTDFVocab:enables TrajectoryGenerationService
]
instance SimulationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Physics engine enabling trajectory simulation and confidence bounds"
    DTDFVocab:enables SimulationService
]
instance ContinuousValidationEnabler : DTDFVocab:Enabler [
    base:desc "Service that compares simulated trajectories to logged data and triggers alerts"
    DTDFVocab:enables ContinuousValidationService
]
instance DesignVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Enabler that loads CAD models into the graphical interface for design review"
    DTDFVocab:enables DesignVisualizationService
]

// Services
instance MQTTPublisherService : DTDFVocab:Service [
    base:desc "Publishes CraneTimeSeriesData to the MQTT broker via the Physical Crane Interface"
    DTDFVocab:provides MQTTPublishingInsight
]
instance LoggingIngestionService : DTDFVocab:Service [
    base:desc "Subscribes to MQTT topics and writes received telemetry into TimescaleDB"
    DTDFVocab:provides LogCreationInsight
]
instance DataStorageService : DTDFVocab:Service [
    base:desc "Handles persistence of time‑series telemetry in TimescaleDB"
    DTDFVocab:provides DataPersistedInsight
]
instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Provides real‑time visualization of trajectory adherence, joint positions, and wind speed on Grafana dashboards"
    DTDFVocab:provides RealTimeVisualizationInsight
]
instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Generates optimal trajectories based on current state and kinematic models"
    DTDFVocab:provides TrajectoryGenerationInsight
]
instance SimulationService : DTDFVocab:Service [
    base:desc "Runs trajectory simulations and calculates confidence bounds for validation"
    DTDFVocab:provides TrajectorySimulationInsight
]
instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Compares simulated trajectories against logged data and alerts operators on deviations"
    DTDFVocab:provides TrajectoryValidationInsight
]
instance DesignVisualizationService : DTDFVocab:Service [
    base:desc "Provides visual representation of CAD models to inspectors"
    DTDFVocab:provides CADModelInsight
]

// Insights
instance MQTTPublishingInsight : DTDFVocab:Insight [
    base:desc "Indicates successful data publication to the MQTT broker"
]
instance LogCreationInsight : DTDFVocab:Insight [
    base:desc "Records that a telemetry log entry has been created in TimescaleDB"
]
instance DataPersistedInsight : DTDFVocab:Insight [
    base:desc "Confirms that the telemetry data has been persisted in the database"
]
instance RealTimeVisualizationInsight : DTDFVocab:Insight [
    base:desc "Dashboard reflects current state of the crane in real time"
]
instance TrajectoryGenerationInsight : DTDFVocab:Insight [
    base:desc "Optimal trajectory has been generated using the kinematic model"
]
instance TrajectorySimulationInsight : DTDFVocab:Insight [
    base:desc "Simulation of trajectory and associated confidence bounds completed"
]
instance TrajectoryValidationInsight : DTDFVocab:Insight [
    base:desc "Deviation between simulated and logged trajectory has been evaluated"
]
instance CADModelInsight : DTDFVocab:Insight [
    base:desc "Indicates CAD model has been visualized"
]

// Acting Components
instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the cart axis, controlled via a TMC4671‑Eval driver"
]
