instance SimulationModel : DTDFVocab:Model [
    base:desc "Simulation model used to validate trajectories and compute confidence bounds"
    DTDFVocab:inputTo SimulationEngineEnabler
]

// Historical Data
instance HistoricalTimeSeriesData : DTDFVocab:Data [
    base:desc "Historical telemetry logs stored in TimescaleDB for analysis and validation"
    DTDFVocab:inputTo TimescaleDBEnabler
    DTDFVocab:fromData CraneTelemetryTransmitted
]

